{
  "name": "Visionary AI Studio",
  "description": "A comprehensive AI generation studio featuring Text-to-Image, Image-to-Image editing, and Text-to-Video creation using Google's latest Gemini and Veo models."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum GenerationMode {
  TEXT_TO_IMAGE = 'TEXT_TO_IMAGE',
  IMAGE_TO_IMAGE = 'IMAGE_TO_IMAGE',
  TEXT_TO_VIDEO = 'TEXT_TO_VIDEO'
}

export interface GeneratedContent {
  id: string;
  type: 'image' | 'video';
  url: string;
  prompt: string;
  timestamp: number;
}

export type AspectRatio = "1:1" | "3:4" | "4:3" | "9:16" | "16:9";

export interface ImageGenerationOptions {
  prompt: string;
  aspectRatio: AspectRatio;
  baseImage?: string; // Base64 for Img2Img
}

export interface VideoGenerationOptions {
  prompt: string;
  aspectRatio: "16:9" | "9:16";
  resolution: "720p" | "1080p";
}

// Augment window for Veo API key selection
declare global {
  interface Window {
    aistudio?: {
      hasSelectedApiKey: () => Promise<boolean>;
      openSelectKey: () => Promise<void>;
    };
  }
}

import { GoogleGenAI } from "@google/genai";
import { ImageGenerationOptions, VideoGenerationOptions } from "../types";

// Helper to get a fresh instance (important for Veo key selection updates)
const getAIClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateImage = async (options: ImageGenerationOptions): Promise<string> => {
  const ai = getAIClient();
  const { prompt, aspectRatio, baseImage } = options;

  const parts: any[] = [];

  // If baseImage exists, it's Image-to-Image
  if (baseImage) {
    // baseImage should be raw base64 data (without data:image/png;base64 prefix if possible, 
    // but the inlineData accepts it cleaner if we strip the prefix)
    const cleanBase64 = baseImage.split(',')[1] || baseImage;
    parts.push({
      inlineData: {
        data: cleanBase64,
        mimeType: 'image/png' // Assuming PNG or JPEG, GenAI is flexible
      }
    });
  }

  parts.push({ text: prompt });

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image', // Standard model for both T2I and I2I
    contents: {
      parts: parts
    },
    config: {
      imageConfig: {
        aspectRatio: aspectRatio,
      }
    }
  });

  // Extract image from response
  if (response.candidates?.[0]?.content?.parts) {
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData && part.inlineData.data) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
  }

  throw new Error("No image data found in response");
};

export const generateVideo = async (options: VideoGenerationOptions): Promise<string> => {
  const ai = getAIClient();

  // Start the operation
  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: options.prompt,
    config: {
      numberOfVideos: 1,
      resolution: options.resolution,
      aspectRatio: options.aspectRatio
    }
  });

  // Poll for completion
  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 5000)); // Poll every 5s
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  const videoUri = operation.response?.generatedVideos?.[0]?.video?.uri;

  if (!videoUri) {
    throw new Error("Video generation failed: No URI returned.");
  }

  // Fetch the actual video bytes using the key
  const fetchUrl = `${videoUri}&key=${process.env.API_KEY}`;
  const response = await fetch(fetchUrl);

  if (!response.ok) {
    throw new Error(`Failed to download video: ${response.statusText}`);
  }

  const blob = await response.blob();
  return URL.createObjectURL(blob);
};

export const checkVeoKeyStatus = async (): Promise<boolean> => {
  if (window.aistudio?.hasSelectedApiKey) {
    return await window.aistudio.hasSelectedApiKey();
  }
  return true; // Fallback if not running in specific environment, assume env key is fine
};

export const requestVeoKeySelection = async (): Promise<void> => {
  if (window.aistudio?.openSelectKey) {
    await window.aistudio.openSelectKey();
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  className = '', 
  disabled, 
  ...props 
}) => {
  const baseStyles = "px-6 py-3 rounded-xl font-medium transition-all duration-200 flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed transform active:scale-95";

  const variants = {
    primary: "bg-gradient-to-r from-primary to-secondary text-white hover:shadow-lg hover:shadow-primary/25 border border-transparent",
    secondary: "bg-surface text-white hover:bg-slate-700 border border-slate-700",
    outline: "bg-transparent text-white border border-slate-600 hover:border-primary hover:text-primary",
    ghost: "bg-transparent text-slate-400 hover:text-white hover:bg-white/5"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${className}`}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading && (
        <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
        </svg>
      )}
      {children}
    </button>
  );
};

import React from 'react';

