import React, { useState } from 'react';
import { generateImage } from '../services/gemini';
import { Button } from './ui/Button';
import { TextArea } from './ui/Input';
import { AspectRatio } from '../types';

interface TextToImageProps {
  onGenerate: (url: string, type: 'image') => void;
}

export const TextToImage: React.FC<TextToImageProps> = ({ onGenerate }) => {
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>('1:1');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async () => {
    if (!prompt.trim()) return;

    setIsLoading(true);
    setError(null);

    try {
      const imageUrl = await generateImage({
        prompt,
        aspectRatio
      });
      onGenerate(imageUrl, 'image');
    } catch (err: any) {
      setError(err.message || 'Failed to generate image');
    } finally {
      setIsLoading(false);
    }
  };

  const ratios: AspectRatio[] = ["1:1", "3:4", "4:3", "9:16", "16:9"];

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="bg-surface/50 p-6 rounded-2xl border border-slate-800 backdrop-blur-sm">
        <h2 className="text-xl font-semibold mb-4 text-white flex items-center gap-2">
          <svg className="w-5 h-5 text-primary" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
          Text to Image
        </h2>

        <div className="space-y-4">
          <TextArea
            label="What do you want to see?"
            placeholder="A futuristic city with flying cars at sunset, cyberpunk style..."
            rows={4}
            value={prompt}
            onChange={(e) => setPrompt(e.target.value)}
          />

          <div>
            <label className="block text-sm font-medium text-slate-300 mb-2">Aspect Ratio</label>
            <div className="flex flex-wrap gap-2">
              {ratios.map((r) => (
                <button
                  key={r}
                  onClick={() => setAspectRatio(r)}
                  className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
                    aspectRatio === r 
                      ? 'bg-primary text-white shadow-lg shadow-primary/20' 
                      : 'bg-slate-800 text-slate-400 hover:bg-slate-700 hover:text-white'
                  }`}
                >
                  {r}
                </button>
              ))}
            </div>
          </div>
        </div>

        {error && (
          <div className="mt-4 p-4 bg-red-500/10 border border-red-500/20 rounded-xl text-red-400 text-sm">
            {error}
          </div>
        )}

        <div className="mt-6">
          <Button 
            onClick={handleGenerate} 
            isLoading={isLoading} 
            className="w-full"
            disabled={!prompt.trim()}
          >
            {isLoading ? 'Dreaming...' : 'Generate Image'}
          </Button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { generateImage } from '../services/gemini';
import { Button } from './ui/Button';
import { TextArea } from './ui/Input';
import { AspectRatio } from '../types';

interface ImageToImageProps {
  onGenerate: (url: string, type: 'image') => void;
}

export const ImageToImage: React.FC<ImageToImageProps> = ({ onGenerate }) => {
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>('1:1');
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) { // 5MB limit check
        setError("File size too large. Please select an image under 5MB.");
        return;
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
        setError(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!prompt.trim() || !selectedImage) return;

    setIsLoading(true);
    setError(null);

    try {
      const imageUrl = await generateImage({
        prompt,
        aspectRatio,
        baseImage: selectedImage
      });
      onGenerate(imageUrl, 'image');
    } catch (err: any) {
      setError(err.message || 'Failed to generate image');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="bg-surface/50 p-6 rounded-2xl border border-slate-800 backdrop-blur-sm">
        <h2 className="text-xl font-semibold mb-4 text-white flex items-center gap-2">
          <svg className="w-5 h-5 text-secondary" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
          Image to Image
        </h2>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-4">
             {/* Image Upload Area */}
             <div 
                onClick={() => fileInputRef.current?.click()}
                className={`relative h-64 border-2 border-dashed rounded-xl flex flex-col items-center justify-center cursor-pointer transition-all overflow-hidden group ${
                  selectedImage ? 'border-primary/50' : 'border-slate-700 hover:border-slate-500 hover:bg-slate-800/50'
                }`}
              >
                {selectedImage ? (
                  <>
                    <img src={selectedImage} alt="Reference" className="w-full h-full object-contain p-2" />
                    <div className="absolute inset-0 bg-black/60 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                      <span className="text-white font-medium">Click to change</span>
                    </div>
                  </>
                ) : (
                  <div className="text-center p-4">
                    <svg className="w-10 h-10 text-slate-500 mx-auto mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                    <p className="text-slate-400 font-medium">Click to upload reference image</p>
                    <p className="text-slate-600 text-xs mt-1">PNG, JPG up to 5MB</p>
                  </div>
                )}
                <input 
                  type="file" 
                  ref={fileInputRef}
                  className="hidden" 
                  accept="image/*"
                  onChange={handleFileChange}
                />
              </div>
          </div>

          <div className="space-y-4">
            <TextArea
              label="How should we change it?"
              placeholder="Make it look like a van gogh painting, add snow, turn day to night..."
              rows={6}
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              className="h-[160px]"
            />
          </div>
        </div>

        {error && (
          <div className="mt-4 p-4 bg-red-500/10 border border-red-500/20 rounded-xl text-red-400 text-sm">
            {error}
          </div>
        )}

        <div className="mt-6">
          <Button 
            onClick={handleGenerate} 
            isLoading={isLoading} 
            className="w-full"
            disabled={!prompt.trim() || !selectedImage}
          >
            {isLoading ? 'Transforming...' : 'Generate Variation'}
          </Button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { generateVideo, checkVeoKeyStatus, requestVeoKeySelection } from '../services/gemini';
import { Button } from './ui/Button';
import { TextArea } from './ui/Input';

interface TextToVideoProps {
  onGenerate: (url: string, type: 'video') => void;
}

export const TextToVideo: React.FC<TextToVideoProps> = ({ onGenerate }) => {
  const [prompt, setPrompt] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [hasPaidKey, setHasPaidKey] = useState<boolean>(true); // Optimistic default
  const [statusMessage, setStatusMessage] = useState<string>('');

  useEffect(() => {
    checkKeyStatus();
  }, []);

  const checkKeyStatus = async () => {
    try {
      const status = await checkVeoKeyStatus();
      setHasPaidKey(status);
    } catch (e) {
      console.warn("Failed to check API key status", e);
    }
  };

  const handleKeySelection = async () => {
    try {
      await requestVeoKeySelection();
      // Assume success as per instructions to avoid race condition delays
      setHasPaidKey(true);
    } catch (e) {
      console.error(e);
      setError("Failed to open key selection dialog.");
    }
  };

  const handleGenerate = async () => {
    if (!prompt.trim()) return;

    if (!hasPaidKey) {
      await handleKeySelection();
      return; 
    }

    setIsLoading(true);
    setError(null);
    setStatusMessage('Initializing Veo model...');

    try {
      setStatusMessage('Dreaming up frames (this may take a minute)...');

      const videoUrl = await generateVideo({
        prompt,
        aspectRatio: '16:9',
        resolution: '720p' // Default for speed
      });

      onGenerate(videoUrl, 'video');
    } catch (err: any) {
      if (err.message && err.message.includes('Requested entity was not found')) {
         // Reset key if we get the specific error mentioning entity not found (often key related context)
         setHasPaidKey(false);
         setError("Authorization failed. Please select a valid paid API key.");
      } else {
        setError(err.message || 'Failed to generate video');
      }
    } finally {
      setIsLoading(false);
      setStatusMessage('');
    }
  };

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="bg-surface/50 p-6 rounded-2xl border border-slate-800 backdrop-blur-sm">
        <h2 className="text-xl font-semibold mb-4 text-white flex items-center gap-2">
          <svg className="w-5 h-5 text-pink-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
          Text to Video (Veo)
        </h2>

        {!hasPaidKey ? (
          <div className="p-8 bg-slate-900/50 rounded-xl border border-slate-700 text-center space-y-4">
            <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-slate-800 mb-2">
              <svg className="w-8 h-8 text-yellow-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 7a2 2 0 012 2m4 0a6 6 0 01-7.743 5.743L11 17H9v2H7v2H4a1 1 0 01-1-1v-2.586a1 1 0 01.293-.707l5.964-5.964A6 6 0 1121 9z" /></svg>
            </div>
            <h3 className="text-lg font-medium text-white">Unlock Veo Video Generation</h3>
            <p className="text-slate-400 max-w-md mx-auto">
              Generating high-quality video requires a paid API key from Google Cloud Project. 
              See <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" rel="noreferrer" className="text-primary hover:underline">billing documentation</a>.
            </p>
            <Button onClick={handleKeySelection} className="mx-auto mt-4">
              Select Paid API Key
            </Button>
          </div>
        ) : (
          <>
            <div className="space-y-4">
              <TextArea
                label="Describe your video"
                placeholder="A cinematic drone shot of a cyberpunk city in rain, neon lights reflecting on wet streets, 4k, highly detailed..."
                rows={4}
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
              />
            </div>

            {statusMessage && (
              <div className="mt-4 flex items-center gap-3 text-sm text-blue-300 bg-blue-500/10 p-3 rounded-lg border border-blue-500/20">
                <span className="relative flex h-3 w-3">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-blue-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-3 w-3 bg-blue-500"></span>
                </span>
                {statusMessage}
              </div>
            )}

            {error && (
              <div className="mt-4 p-4 bg-red-500/10 border border-red-500/20 rounded-xl text-red-400 text-sm">
                {error}
              </div>
            )}

            <div className="mt-6">
              <Button 
                onClick={handleGenerate} 
                isLoading={isLoading} 
                className="w-full"
                disabled={!prompt.trim()}
              >
                {isLoading ? 'Generating Video...' : 'Generate Video'}
              </Button>
            </div>
          </>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { GenerationMode, GeneratedContent } from './types';
import { TextToImage } from './components/TextToImage';
import { ImageToImage } from './components/ImageToImage';
import { TextToVideo } from './components/TextToVideo';

const App = () => {
  const [mode, setMode] = useState<GenerationMode>(GenerationMode.TEXT_TO_IMAGE);
  const [history, setHistory] = useState<GeneratedContent[]>([]);
  const [activeContent, setActiveContent] = useState<GeneratedContent | null>(null);

  const handleGenerationSuccess = (url: string, type: 'image' | 'video') => {
    const newContent: GeneratedContent = {
      id: Date.now().toString(),
      type,
      url,
      prompt: "Generated Content", // In a real app we'd pass the prompt back up too
      timestamp: Date.now()
    };
    setHistory(prev => [newContent, ...prev]);
    setActiveContent(newContent);
  };

  return (
    <div className="min-h-screen bg-darker text-slate-200 font-sans selection:bg-primary/30">
      {/* Header */}
      <header className="fixed top-0 left-0 right-0 z-50 bg-darker/80 backdrop-blur-md border-b border-slate-800">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
