              <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
            </div>
            <span className="font-bold text-xl tracking-tight text-white">Visionary AI</span>
          </div>
          <div className="hidden md:flex items-center gap-6 text-sm font-medium text-slate-400">
             <span>Gemini 2.5 Flash</span>
             <span>Veo 3.1</span>
          </div>
        </div>
      </header>

      <main className="pt-24 pb-12 px-4 max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Sidebar / Navigation */}
        <div className="lg:col-span-3 space-y-6">
          <nav className="space-y-1">
            <button
              onClick={() => setMode(GenerationMode.TEXT_TO_IMAGE)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${
                mode === GenerationMode.TEXT_TO_IMAGE 
                  ? 'bg-surface text-white shadow-lg shadow-black/20 border border-slate-700' 
                  : 'text-slate-400 hover:text-white hover:bg-surface/50'
              }`}
            >
              <svg className="w-5 h-5 text-primary" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
              <span className="font-medium">Text to Image</span>
            </button>
            <button
              onClick={() => setMode(GenerationMode.IMAGE_TO_IMAGE)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${
                mode === GenerationMode.IMAGE_TO_IMAGE 
                  ? 'bg-surface text-white shadow-lg shadow-black/20 border border-slate-700' 
                  : 'text-slate-400 hover:text-white hover:bg-surface/50'
              }`}
            >
              <svg className="w-5 h-5 text-secondary" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
              <span className="font-medium">Image to Image</span>
            </button>
            <button
              onClick={() => setMode(GenerationMode.TEXT_TO_VIDEO)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${
                mode === GenerationMode.TEXT_TO_VIDEO 
                  ? 'bg-surface text-white shadow-lg shadow-black/20 border border-slate-700' 
                  : 'text-slate-400 hover:text-white hover:bg-surface/50'
              }`}
            >
              <svg className="w-5 h-5 text-pink-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
              <span className="font-medium">Text to Video</span>
            </button>
          </nav>

          {/* Recent History Sidebar */}
          <div className="hidden lg:block">
            <h3 className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-4 px-4">Recent Creations</h3>
            <div className="space-y-2">
              {history.length === 0 ? (
                <p className="text-sm text-slate-600 px-4">No creations yet.</p>
              ) : (
                history.map(item => (
                  <div 
                    key={item.id}
                    onClick={() => setActiveContent(item)}
                    className={`group flex items-center gap-3 p-2 rounded-lg cursor-pointer transition-colors ${
                      activeContent?.id === item.id ? 'bg-surface border border-slate-700' : 'hover:bg-surface/50'
                    }`}
                  >
                    {item.type === 'video' ? (
                      <div className="w-12 h-12 bg-black rounded overflow-hidden flex-shrink-0 flex items-center justify-center border border-slate-700">
                         <video src={item.url} className="w-full h-full object-cover opacity-50" />
                         <div className="absolute"><svg className="w-4 h-4 text-white" fill="currentColor" viewBox="0 0 20 20"><path d="M6.3 2.841A1.5 1.5 0 004 4.11V15.89a1.5 1.5 0 002.3 1.269l9.344-5.89a1.5 1.5 0 000-2.538L6.3 2.84z" /></svg></div>
                      </div>
                    ) : (
                      <img src={item.url} alt="Thumbnail" className="w-12 h-12 rounded object-cover border border-slate-700" />
                    )}
                    <div className="flex-1 min-w-0">
                      <p className="text-sm text-slate-300 truncate">{item.type === 'video' ? 'Video Generation' : 'Image Generation'}</p>
                      <p className="text-xs text-slate-500">{new Date(item.timestamp).toLocaleTimeString()}</p>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>

        {/* Main Content Area */}
        <div className="lg:col-span-9 space-y-8">

          {/* Active Result Display */}
          {activeContent && (
             <div className="rounded-3xl overflow-hidden bg-black/50 border border-slate-800 shadow-2xl relative group">
                {activeContent.type === 'video' ? (
                  <video 
                    src={activeContent.url} 
                    controls 
                    autoPlay 
                    loop 
                    className="w-full max-h-[600px] object-contain mx-auto"
                  />
                ) : (
                  <img 
                    src={activeContent.url} 
                    alt="Result" 
                    className="w-full max-h-[600px] object-contain mx-auto"
                  />
                )}

                <div className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-opacity">
                  <a 
                    href={activeContent.url} 
                    download={`visionary-ai-${activeContent.id}.${activeContent.type === 'video' ? 'mp4' : 'png'}`}
                    className="p-2 bg-black/60 hover:bg-primary text-white rounded-lg backdrop-blur-sm transition-colors block"
                    title="Download"
                  >
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                  </a>
                </div>
             </div>
          )}

          {/* Generator Form */}
          <div className="relative">
            {mode === GenerationMode.TEXT_TO_IMAGE && <TextToImage onGenerate={handleGenerationSuccess} />}
            {mode === GenerationMode.IMAGE_TO_IMAGE && <ImageToImage onGenerate={handleGenerationSuccess} />}
            {mode === GenerationMode.TEXT_TO_VIDEO && <TextToVideo onGenerate={handleGenerationSuccess} />}
          </div>

        </div>
      </main>
    </div>
  );
};

export default App;

