import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  className = '', 
  disabled, 
  ...props 
}) => {
  // Minimalist, rounded-md, distinct focus states
  const baseStyles = "inline-flex items-center justify-center rounded-md text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-zinc-400 disabled:pointer-events-none disabled:opacity-50 h-10 px-4 py-2";

  const variants = {
    primary: "bg-primary text-primary-foreground hover:bg-primary/90 shadow-[0_0_15px_rgba(255,255,255,0.1)]",
    secondary: "bg-zinc-800 text-zinc-100 hover:bg-zinc-700 shadow-sm",
    outline: "border border-border bg-transparent hover:bg-accent text-foreground",
    ghost: "hover:bg-accent hover:text-foreground text-muted"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${className}`}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading && (
        <svg className="animate-spin -ml-1 mr-2 h-4 w-4" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
        </svg>
      )}
      {children}
    </button>
  );
};

import React from 'react';

interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
  label?: string;
}

interface TextAreaProps extends React.TextareaHTMLAttributes<HTMLTextAreaElement> {
  label?: string;
}

export const Input: React.FC<InputProps> = ({ label, className = '', ...props }) => {
  return (
    <div className="w-full space-y-2">
      {label && <label className="text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70 text-zinc-400">{label}</label>}
      <input
        className={`flex h-10 w-full rounded-md border border-border bg-transparent px-3 py-2 text-sm text-foreground placeholder:text-zinc-600 focus:outline-none focus:ring-1 focus:ring-zinc-500 disabled:cursor-not-allowed disabled:opacity-50 transition-all hover:border-zinc-700 ${className}`}
        {...props}
      />
    </div>
  );
};

export const TextArea: React.FC<TextAreaProps> = ({ label, className = '', ...props }) => {
  return (
    <div className="w-full space-y-2">
      {label && <label className="text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70 text-zinc-400">{label}</label>}
      <textarea
        className={`flex min-h-[100px] w-full rounded-md border border-border bg-transparent px-3 py-2 text-sm text-foreground placeholder:text-zinc-600 focus:outline-none focus:ring-1 focus:ring-zinc-500 disabled:cursor-not-allowed disabled:opacity-50 transition-all resize-none hover:border-zinc-700 ${className}`}
        {...props}
      />
    </div>
  );
};

import React, { useState } from 'react';
import { GenerationMode, GeneratedContent } from './types';
import { TextToImage } from './components/TextToImage';
import { ImageToImage } from './components/ImageToImage';
import { TextToVideo } from './components/TextToVideo';

const App = () => {
  const [mode, setMode] = useState<GenerationMode>(GenerationMode.TEXT_TO_IMAGE);
  const [history, setHistory] = useState<GeneratedContent[]>([]);
  const [activeContent, setActiveContent] = useState<GeneratedContent | null>(null);

  const handleGenerationSuccess = (url: string, type: 'image' | 'video') => {
    const newContent: GeneratedContent = {
      id: Date.now().toString(),
      type,
      url,
      prompt: "Generated Content",
      timestamp: Date.now()
    };
    setHistory(prev => [newContent, ...prev]);
    setActiveContent(newContent);
  };

  const NavItem = ({ 
    active, 
    onClick, 
    icon, 
    label 
  }: { 
    active: boolean; 
    onClick: () => void; 
    icon: React.ReactNode; 
    label: string;
  }) => (
    <button
      onClick={onClick}
      className={`w-full flex items-center gap-3 px-3 py-2 rounded-md text-sm font-medium transition-colors ${
        active 
          ? 'bg-zinc-900 text-white' 
          : 'text-zinc-500 hover:text-white hover:bg-zinc-900/50'
      }`}
    >
      {icon}
      {label}
    </button>
  );

  return (
    <div className="min-h-screen bg-background flex text-foreground font-sans">

      {/* Sidebar */}
      <aside className="w-64 border-r border-border bg-sidebar flex-shrink-0 flex flex-col fixed top-0 bottom-0 left-0 z-20">
