import React, { useState } from 'react';
import { generateImage } from '../services/gemini';
import { Button } from './ui/Button';
import { TextArea } from './ui/Input';
import { AspectRatio } from '../types';

interface TextToImageProps {
  onGenerate: (url: string, type: 'image') => void;
}

export const TextToImage: React.FC<TextToImageProps> = ({ onGenerate }) => {
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>('1:1');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async () => {
    if (!prompt.trim()) return;

    setIsLoading(true);
    setError(null);

    try {
      const imageUrl = await generateImage({
        prompt,
        aspectRatio
      });
      onGenerate(imageUrl, 'image');
    } catch (err: any) {
      setError(err.message || 'Failed to generate image');
    } finally {
      setIsLoading(false);
    }
  };

  const ratios: AspectRatio[] = ["1:1", "3:4", "4:3", "9:16", "16:9"];

  return (
    <div className="glass-panel p-6 rounded-2xl relative overflow-hidden">
      {/* Decorative Glow */}
      <div className="absolute top-0 right-0 w-32 h-32 bg-primary/20 blur-[60px] rounded-full pointer-events-none"></div>

      <div className="space-y-6 relative z-10">
        <TextArea
          label="PROMPT"
          placeholder="Describe a futuristic cityscape with neon lights, wet pavement, cyberpunk aesthetic, detailed, 8k..."
          rows={5}
          value={prompt}
          onChange={(e) => setPrompt(e.target.value)}
        />

        <div className="space-y-3">
          <label className="text-xs font-semibold uppercase tracking-wider text-gray-400">Aspect Ratio</label>
          <div className="flex flex-wrap gap-2">
            {ratios.map((r) => (
              <button
                key={r}
                onClick={() => setAspectRatio(r)}
                className={`px-4 py-2 rounded-lg text-xs font-bold transition-all border ${
                  aspectRatio === r 
                    ? 'bg-primary text-white border-primary shadow-[0_0_15px_rgba(139,92,246,0.4)]' 
                    : 'bg-black/20 text-gray-400 border-white/5 hover:border-white/20 hover:text-white'
                }`}
              >
                {r}
              </button>
            ))}
          </div>
        </div>

        {error && (
          <div className="p-4 bg-red-500/10 border border-red-500/20 rounded-xl text-red-200 text-sm backdrop-blur-sm">
            {error}
          </div>
        )}

        <div className="pt-2">
          <Button 
            onClick={handleGenerate} 
            isLoading={isLoading} 
            disabled={!prompt.trim()}
            className="w-full"
          >
            {isLoading ? 'GENERATING...' : 'GENERATE ARTWORK'}
          </Button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { generateImage } from '../services/gemini';
import { Button } from './ui/Button';
import { TextArea } from './ui/Input';
import { AspectRatio } from '../types';

interface ImageToImageProps {
  onGenerate: (url: string, type: 'image') => void;
}

export const ImageToImage: React.FC<ImageToImageProps> = ({ onGenerate }) => {
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>('1:1');
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) { 
        setError("File size too large. Please select an image under 5MB.");
        return;
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
        setError(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!prompt.trim() || !selectedImage) return;

    setIsLoading(true);
    setError(null);

    try {
      const imageUrl = await generateImage({
        prompt,
        aspectRatio,
        baseImage: selectedImage
      });
      onGenerate(imageUrl, 'image');
    } catch (err: any) {
      setError(err.message || 'Failed to generate image');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="glass-panel p-6 rounded-2xl">

        <div className="space-y-6">
          <div className="space-y-2">
             <label className="text-xs font-semibold uppercase tracking-wider text-gray-400">Reference</label>
             <div 
                onClick={() => fileInputRef.current?.click()}
                className={`relative h-48 border border-dashed rounded-xl flex flex-col items-center justify-center cursor-pointer transition-all overflow-hidden group ${
                  selectedImage 
                    ? 'border-primary/50 bg-black/40' 
                    : 'border-white/10 bg-black/20 hover:border-white/30 hover:bg-black/30'
                }`}
              >
                {selectedImage ? (
                  <>
                    <img src={selectedImage} alt="Reference" className="w-full h-full object-contain p-4 opacity-80 group-hover:opacity-40 transition-opacity" />
                    <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                      <div className="bg-black/60 backdrop-blur px-4 py-2 rounded-lg border border-white/10">
                         <span className="text-white text-xs font-bold uppercase">Change Image</span>
                      </div>
                    </div>
                  </>
                ) : (
                  <div className="text-center p-4">
                    <div className="w-12 h-12 rounded-full bg-white/5 flex items-center justify-center mx-auto mb-3 group-hover:scale-110 transition-transform shadow-lg shadow-black/20">
                        <svg className="w-6 h-6 text-primary" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                    </div>
                    <p className="text-gray-300 text-sm font-medium">Upload Source</p>
                    <p className="text-gray-600 text-xs mt-1">PNG, JPG up to 5MB</p>
                  </div>
                )}
                <input 
                  type="file" 
                  ref={fileInputRef}
                  className="hidden" 
                  accept="image/*"
                  onChange={handleFileChange}
                />
              </div>
          </div>

          <TextArea
            label="INSTRUCTIONS"
            placeholder="Turn day into night, add cyberpunk neon lights, make it look like an oil painting..."
            rows={4}
            value={prompt}
            onChange={(e) => setPrompt(e.target.value)}
          />

          {error && (
            <div className="p-4 bg-red-500/10 border border-red-500/20 rounded-xl text-red-200 text-sm backdrop-blur-sm">
              {error}
            </div>
          )}

          <Button 
            onClick={handleGenerate} 
            isLoading={isLoading} 
            disabled={!prompt.trim() || !selectedImage}
            className="w-full"
          >
            {isLoading ? 'TRANSFORMING...' : 'GENERATE VARIATION'}
          </Button>
        </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { generateVideo, checkVeoKeyStatus, requestVeoKeySelection } from '../services/gemini';
import { Button } from './ui/Button';
import { TextArea } from './ui/Input';

interface TextToVideoProps {
  onGenerate: (url: string, type: 'video') => void;
}

export const TextToVideo: React.FC<TextToVideoProps> = ({ onGenerate }) => {
  const [prompt, setPrompt] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [hasPaidKey, setHasPaidKey] = useState<boolean>(true);
  const [statusMessage, setStatusMessage] = useState<string>('');

  useEffect(() => {
    checkKeyStatus();
  }, []);

  const checkKeyStatus = async () => {
    try {
      const status = await checkVeoKeyStatus();
      setHasPaidKey(status);
    } catch (e) {
      console.warn("Failed to check API key status", e);
    }
  };

  const handleKeySelection = async () => {
    try {
      await requestVeoKeySelection();
      setHasPaidKey(true);
    } catch (e) {
      console.error(e);
      setError("Failed to open key selection dialog.");
    }
  };

  const handleGenerate = async () => {
    if (!prompt.trim()) return;

    if (!hasPaidKey) {
      await handleKeySelection();
      return; 
    }

    setIsLoading(true);
    setError(null);
    setStatusMessage('INITIALIZING VEO MODEL...');

    try {
      setStatusMessage('DREAMING FRAMES (THIS MAY TAKE A MINUTE)...');

      const videoUrl = await generateVideo({
        prompt,
        aspectRatio: '16:9',
        resolution: '720p'
      });

      onGenerate(videoUrl, 'video');
    } catch (err: any) {
      if (err.message && err.message.includes('Requested entity was not found')) {
         setHasPaidKey(false);
         setError("Authorization failed. Please select a valid paid API key.");
      } else {
        setError(err.message || 'Failed to generate video');
      }
    } finally {
      setIsLoading(false);
      setStatusMessage('');
    }
  };

  return (
    <div className="glass-panel p-6 rounded-2xl relative">
      {/* Decorative Elements */}
      <div className="absolute -bottom-10 -left-10 w-40 h-40 bg-secondary/10 blur-[80px] rounded-full pointer-events-none"></div>

      {!hasPaidKey ? (
        <div className="py-12 px-4 text-center space-y-6 relative z-10">
          <div className="w-16 h-16 rounded-2xl bg-gradient-to-br from-yellow-500 to-orange-500 flex items-center justify-center mx-auto shadow-[0_0_30px_rgba(234,179,8,0.3)]">
            <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 7a2 2 0 012 2m4 0a6 6 0 01-7.743 5.743L11 17H9v2H7v2H4a1 1 0 01-1-1v-2.586a1 1 0 01.293-.707l5.964-5.964A6 6 0 1121 9z" /></svg>
          </div>
          <div>
            <h3 className="text-xl font-display font-bold text-white mb-2">Unlock Veo Studio</h3>
            <p className="text-gray-400 text-sm max-w-sm mx-auto leading-relaxed">
              Video generation is a premium feature. Please select a project with a paid billing account to access Veo's cinematic capabilities.
            </p>
          </div>
          <Button onClick={handleKeySelection} variant="primary">
            Connect Paid Account
          </Button>
          <div className="text-xs text-gray-500">
             View <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" rel="noreferrer" className="text-primary hover:text-white transition-colors underline">billing documentation</a>
          </div>
        </div>
      ) : (
        <div className="space-y-6 relative z-10">
          <TextArea
            label="SCENE DESCRIPTION"
            placeholder="A cinematic drone shot of a cyberpunk city in rain, neon lights reflecting on wet streets, 4k, highly detailed..."
            rows={5}
            value={prompt}
            onChange={(e) => setPrompt(e.target.value)}
          />

          {statusMessage && (
