};

import React, { useState, useRef } from 'react';
import { generateImage } from '../services/gemini';
import { Button } from './ui/Button';
import { TextArea } from './ui/Input';
import { AspectRatio } from '../types';

interface ImageToImageProps {
  onGenerate: (url: string, type: 'image') => void;
}

export const ImageToImage: React.FC<ImageToImageProps> = ({ onGenerate }) => {
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>('1:1');
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) { // 5MB limit check
        setError("File size too large. Please select an image under 5MB.");
        return;
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
        setError(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!prompt.trim() || !selectedImage) return;

    setIsLoading(true);
    setError(null);

    try {
      const imageUrl = await generateImage({
        prompt,
        aspectRatio,
        baseImage: selectedImage
      });
      onGenerate(imageUrl, 'image');
    } catch (err: any) {
      setError(err.message || 'Failed to generate image');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="rounded-lg border border-border bg-card p-6 shadow-sm">

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <div className="space-y-2">
             <label className="text-sm font-medium leading-none text-zinc-400">Reference Image</label>
             <div 
                onClick={() => fileInputRef.current?.click()}
                className={`relative h-64 border border-dashed rounded-lg flex flex-col items-center justify-center cursor-pointer transition-all overflow-hidden group bg-zinc-900/50 ${
                  selectedImage ? 'border-zinc-700' : 'border-zinc-700 hover:border-zinc-500 hover:bg-zinc-900'
                }`}
              >
                {selectedImage ? (
                  <>
                    <img src={selectedImage} alt="Reference" className="w-full h-full object-contain p-4" />
                    <div className="absolute inset-0 bg-black/60 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity backdrop-blur-sm">
                      <span className="text-white text-sm font-medium">Replace Image</span>
                    </div>
                  </>
                ) : (
                  <div className="text-center p-4">
                    <div className="w-10 h-10 rounded-full bg-zinc-800 flex items-center justify-center mx-auto mb-3">
                        <svg className="w-5 h-5 text-zinc-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                    </div>
                    <p className="text-zinc-300 text-sm font-medium">Upload Reference</p>
                    <p className="text-zinc-500 text-xs mt-1">PNG, JPG up to 5MB</p>
                  </div>
                )}
                <input 
                  type="file" 
                  ref={fileInputRef}
                  className="hidden" 
                  accept="image/*"
                  onChange={handleFileChange}
                />
              </div>
          </div>

          <div className="space-y-6">
            <TextArea
              label="Prompt"
              placeholder="Make it look like a van gogh painting, add snow, turn day to night..."
              rows={8}
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              className="h-full"
            />
          </div>
        </div>

        {error && (
          <div className="mt-6 p-3 bg-red-900/20 border border-red-900/50 rounded-md text-red-400 text-sm">
            {error}
          </div>
        )}

        <div className="mt-6">
          <Button 
            onClick={handleGenerate} 
            isLoading={isLoading} 
            disabled={!prompt.trim() || !selectedImage}
          >
            {isLoading ? 'Transforming...' : 'Generate Variation'}
          </Button>
        </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { generateVideo, checkVeoKeyStatus, requestVeoKeySelection } from '../services/gemini';
import { Button } from './ui/Button';
import { TextArea } from './ui/Input';

interface TextToVideoProps {
  onGenerate: (url: string, type: 'video') => void;
}

export const TextToVideo: React.FC<TextToVideoProps> = ({ onGenerate }) => {
  const [prompt, setPrompt] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [hasPaidKey, setHasPaidKey] = useState<boolean>(true); // Optimistic default
  const [statusMessage, setStatusMessage] = useState<string>('');

  useEffect(() => {
    checkKeyStatus();
  }, []);

  const checkKeyStatus = async () => {
    try {
      const status = await checkVeoKeyStatus();
      setHasPaidKey(status);
    } catch (e) {
      console.warn("Failed to check API key status", e);
    }
  };

  const handleKeySelection = async () => {
    try {
      await requestVeoKeySelection();
      setHasPaidKey(true);
    } catch (e) {
      console.error(e);
      setError("Failed to open key selection dialog.");
    }
  };

  const handleGenerate = async () => {
    if (!prompt.trim()) return;

    if (!hasPaidKey) {
      await handleKeySelection();
      return; 
    }

    setIsLoading(true);
    setError(null);
    setStatusMessage('Initializing Veo model...');

    try {
      setStatusMessage('Dreaming up frames (this may take a minute)...');

      const videoUrl = await generateVideo({
        prompt,
        aspectRatio: '16:9',
        resolution: '720p'
      });

      onGenerate(videoUrl, 'video');
    } catch (err: any) {
      if (err.message && err.message.includes('Requested entity was not found')) {
         setHasPaidKey(false);
         setError("Authorization failed. Please select a valid paid API key.");
      } else {
        setError(err.message || 'Failed to generate video');
      }
    } finally {
      setIsLoading(false);
      setStatusMessage('');
    }
  };

  return (
    <div className="rounded-lg border border-border bg-card p-6 shadow-sm">

        {!hasPaidKey ? (
          <div className="py-12 px-4 text-center space-y-4">
            <div className="inline-flex items-center justify-center w-12 h-12 rounded-full bg-zinc-900 border border-zinc-800 mb-2">
              <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 7a2 2 0 012 2m4 0a6 6 0 01-7.743 5.743L11 17H9v2H7v2H4a1 1 0 01-1-1v-2.586a1 1 0 01.293-.707l5.964-5.964A6 6 0 1121 9z" /></svg>
            </div>
            <h3 className="text-lg font-medium text-white">Unlock Veo Video Generation</h3>
            <p className="text-zinc-400 max-w-sm mx-auto text-sm">
              Generating high-quality video requires a paid API key from Google Cloud Project. 
            </p>
            <div className="pt-2">
              <Button onClick={handleKeySelection} variant="secondary">
                Select Paid API Key
              </Button>
            </div>
            <p className="text-xs text-zinc-600">
               See <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" rel="noreferrer" className="text-zinc-400 hover:underline">billing documentation</a>.
            </p>
