import React, { useState } from 'react';
import { generateImage } from '../services/gemini';
import { Button } from './ui/Button';
import { TextArea } from './ui/Input';
import { AspectRatio } from '../types';

interface TextToImageProps {
  onGenerate: (url: string, type: 'image') => void;
}

export const TextToImage: React.FC<TextToImageProps> = ({ onGenerate }) => {
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>('1:1');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async () => {
    if (!prompt.trim()) return;

    setIsLoading(true);
    setError(null);

    try {
      const imageUrl = await generateImage({
        prompt,
        aspectRatio
      });
      onGenerate(imageUrl, 'image');
    } catch (err: any) {
      setError(err.message || 'Failed to generate image');
    } finally {
      setIsLoading(false);
    }
  };

  const ratios: AspectRatio[] = ["1:1", "3:4", "4:3", "9:16", "16:9"];

  return (
    <div className="p-4 lg:p-6">
      <div className="space-y-6">
        <TextArea
          label="Prompt"
          placeholder="A cyberpunk street in rain, neon lights reflection, 8k..."
          rows={4}
          value={prompt}
          onChange={(e) => setPrompt(e.target.value)}
        />

        <div className="space-y-3">
          <label className="text-xs font-bold uppercase tracking-wider text-gray-500">Aspect Ratio</label>
          <div className="grid grid-cols-5 gap-2">
            {ratios.map((r) => (
              <button
                key={r}
                onClick={() => setAspectRatio(r)}
                className={`py-2 rounded-lg text-xs font-bold transition-all border ${
                  aspectRatio === r 
                    ? 'bg-indigo-600 text-white border-indigo-500 shadow-lg shadow-indigo-500/25' 
                    : 'bg-white/5 text-gray-400 border-white/5 hover:bg-white/10'
                }`}
              >
                {r}
              </button>
            ))}
          </div>
        </div>

        {error && (
          <div className="p-4 bg-red-500/10 border border-red-500/20 rounded-xl text-red-200 text-sm backdrop-blur-sm">
            {error}
          </div>
        )}

        <div className="pt-2">
          <Button 
            onClick={handleGenerate} 
            isLoading={isLoading} 
            disabled={!prompt.trim()}
            className="w-full"
            variant="primary"
          >
            {isLoading ? 'Generating...' : 'Generate Art'}
          </Button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { generateImage } from '../services/gemini';
import { Button } from './ui/Button';
import { TextArea } from './ui/Input';
import { AspectRatio } from '../types';

interface ImageToImageProps {
  onGenerate: (url: string, type: 'image') => void;
}

export const ImageToImage: React.FC<ImageToImageProps> = ({ onGenerate }) => {
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>('1:1');
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) { 
        setError("File size too large. Please select an image under 5MB.");
        return;
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
        setError(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!prompt.trim() || !selectedImage) return;

    setIsLoading(true);
    setError(null);

    try {
      const imageUrl = await generateImage({
        prompt,
        aspectRatio,
        baseImage: selectedImage
      });
      onGenerate(imageUrl, 'image');
    } catch (err: any) {
      setError(err.message || 'Failed to generate image');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="p-4 lg:p-6">
        <div className="space-y-6">
          <div className="space-y-2">
             <label className="text-xs font-bold uppercase tracking-wider text-gray-500">Source Image</label>
             <div 
                onClick={() => fileInputRef.current?.click()}
                className={`relative h-48 border border-dashed rounded-xl flex flex-col items-center justify-center cursor-pointer transition-all overflow-hidden group ${
                  selectedImage 
                    ? 'border-indigo-500/50 bg-black/40' 
                    : 'border-white/10 bg-black/20 hover:border-white/30 hover:bg-black/30'
                }`}
              >
                {selectedImage ? (
                  <>
                    <img src={selectedImage} alt="Reference" className="w-full h-full object-contain p-4 opacity-80 group-hover:opacity-40 transition-opacity" />
                    <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                      <div className="bg-black/80 backdrop-blur px-3 py-1 rounded-full border border-white/10">
                         <span className="text-white text-xs font-bold">Replace</span>
                      </div>
                    </div>
                  </>
                ) : (
                  <div className="text-center p-4">
                    <div className="w-12 h-12 rounded-full bg-white/5 flex items-center justify-center mx-auto mb-3">
