    }

    try {
      genAI = new GoogleGenerativeAI(apiKey);
      model = genAI.getGenerativeModel({ model: "gemini-1.0-pro-001" });
      embeddings = genAI.getEmbeddingsModel({ model: "embedding-001" });
      return true;

    } catch (error) {
        console.error("Failed to initialize Google Generative AI:", error);
        return false;
    }
}

